// lista-pdf.js — PDF 'Lista de Pasajeros' con diseño de plantilla oficial
// Requiere pdfmake (cargado antes de este script)

(function() {

var _HEADER_IMG = 'data:image/png;base64,';
var _FOOTER_IMG = 'data:image/png;base64,';


function getRowsFromMap(seatsMap) {
  var rows = new Set();
  Object.keys(seatsMap || {}).forEach(function(code) {
    var m = code.match(/^(\d+)[A-Z]$/i);
    if (!m) return;
    var st = (seatsMap[code].estado || '').toLowerCase().trim();
    if (st !== 'inhabilitado') rows.add(parseInt(m[1], 10));
  });
  return Array.from(rows).sort(function(a, b) { return a - b; });
}

function buildSeatList() {
  var entries = [];
  if (typeof STAFF_CONTROL_MULTI !== 'undefined' && STAFF_CONTROL_MULTI && typeof STAFF_SHEETS !== 'undefined') {
    var ordered = [];
    var alta = STAFF_SHEETS.find(function(f) { return f.label.toLowerCase().indexOf('alta') >= 0; });
    var baja = STAFF_SHEETS.find(function(f) { return f.label.toLowerCase().indexOf('baja') >= 0; });
    if (alta) ordered.push(alta);
    if (baja) ordered.push(baja);
    STAFF_SHEETS.forEach(function(f) {
      if (!ordered.find(function(o) { return o.sheetName === f.sheetName; })) ordered.push(f);
    });
    var seatNum = 1;
    for (var i = 0; i < ordered.length; i++) {
      var seatsMap = STAFF_SEATS_BY_SHEET.get(ordered[i].sheetName) || {};
      var rows = getRowsFromMap(seatsMap);
      rows.forEach(function(row) {
        ['A','B','C','D'].forEach(function(letter) {
          var code = (row + letter).toUpperCase();
          if (!seatsMap.hasOwnProperty(code)) return;
          var st = (seatsMap[code].estado || '').toLowerCase().trim();
          if (st === 'inhabilitado') return;
          entries.push({ num: seatNum, ci: seatsMap[code].ci || '', pasajero: seatsMap[code].pasajero || '' });
          seatNum++;
        });
      });
    }
  } else if (typeof SEATS !== 'undefined') {
    var rows2 = getRowsFromMap(SEATS);
    var sn = 1;
    rows2.forEach(function(row) {
      ['A','B','C','D'].forEach(function(letter) {
        var code = (row + letter).toUpperCase();
        if (!SEATS.hasOwnProperty(code)) return;
        var st = (SEATS[code].estado || '').toLowerCase().trim();
        if (st === 'inhabilitado') return;
        entries.push({ num: sn, ci: SEATS[code].ci || '', pasajero: SEATS[code].pasajero || '' });
        sn++;
      });
    });
  }
  return entries;
}

// Builds one page definition (header + table + footer), always exactly 35 rows shown
function buildPage(seats, fromNum, toNum, addPageBreak) {
  var COL_BORDER = '#222222';
  var colWidths = [22, 80, 160, 55, 60, 60, 60];
  var ROW_H = 13.3; // pt — calculated to fit A4 exactly with 35 rows

  // Build table rows
  var tableBody = [];

  // Header row
  var hdrLabels = ['', 'Documento', 'Nombre y apellido', 'Abonado', 'Por abonar', '', ''];
  tableBody.push(hdrLabels.map(function(txt) {
    return {
      text: txt, fontSize: 7.5, bold: true, alignment: 'center',
      fillColor: '#dce6f1', border: [true, true, true, true],
      margin: [1, 2, 1, 2]
    };
  }));

  for (var n = fromNum; n <= toNum; n++) {
    var seat = null;
    for (var k = 0; k < seats.length; k++) { if (seats[k].num === n) { seat = seats[k]; break; } }
    var ci     = seat ? seat.ci      : '';
    var nombre = seat ? seat.pasajero : '';
    tableBody.push([
      { text: String(n), fontSize: 8, bold: true, alignment: 'left',   border: [true,true,true,true], margin: [2,1,1,1] },
      { text: ci,        fontSize: 8,              alignment: 'center', border: [true,true,true,true], margin: [2,1,2,1] },
      { text: nombre,    fontSize: 8,              alignment: 'left',   border: [true,true,true,true], margin: [3,1,2,1] },
      { text: '', border: [true,true,true,true] },
      { text: '', border: [true,true,true,true] },
      { text: '', border: [true,true,true,true] },
      { text: '', border: [true,true,true,true] }
    ]);
  }

  // Build heights array: header row + N data rows
  var numDataRows = toNum - fromNum + 1;
  var heights = [14]; // header row
  for (var r = 0; r < numDataRows; r++) { heights.push(ROW_H); }

  var pageStack = [
    // Header image
    { image: _HEADER_IMG, width: 539, margin: [0, 0, 0, 5] },

    // Table
    {
      table: {
        widths: colWidths,
        headerRows: 1,
        heights: heights,
        body: tableBody
      },
      layout: {
        hLineWidth: function() { return 0.5; },
        vLineWidth: function() { return 0.5; },
        hLineColor: function() { return COL_BORDER; },
        vLineColor: function() { return COL_BORDER; },
        paddingLeft:   function() { return 0; },
        paddingRight:  function() { return 0; },
        paddingTop:    function() { return 0; },
        paddingBottom: function() { return 0; }
      },
      margin: [0, 0, 0, 5]
    },

    // Footer bar image
    { image: _FOOTER_IMG, width: 539, margin: [0, 0, 0, 0] }
  ];

  if (addPageBreak) {
    pageStack[0].pageBreak = 'before';
  }

  return pageStack;
}

window.doExportListaPdf = function() {
  if (typeof pdfMake === 'undefined') {
    alert('pdfmake no cargó. Recargá la página e intentá de nuevo.');
    return;
  }
  if (typeof CONTROL_AUTH === 'undefined' || !CONTROL_AUTH) {
    if (typeof toast === 'function') toast('Debes iniciar sesión como staff');
    return;
  }

  var seats    = buildSeatList();
  var tripName = (typeof CURRENT_TRIP !== 'undefined' && CURRENT_TRIP.name) ? CURRENT_TRIP.name : '';
  var total    = seats.length > 0 ? seats[seats.length - 1].num : 0;
  if (total === 0) { if (typeof toast === 'function') toast('No hay asientos cargados'); return; }

  var ROWS_PER_PAGE = 35;
  var content = [];
  var isFirst = true;
  var from = 1;

  while (from <= total) {
    var to = Math.min(from + ROWS_PER_PAGE - 1, total);
    var pageItems = buildPage(seats, from, to, !isFirst);
    for (var i = 0; i < pageItems.length; i++) {
      content.push(pageItems[i]);
    }
    from = to + 1;
    isFirst = false;
  }

  var docDef = {
    pageSize: 'A4',
    pageOrientation: 'portrait',
    pageMargins: [28, 8, 28, 8],
    content: content,
    defaultStyle: { font: 'Roboto' }
  };

  var filename = 'Lista_Pasajeros' + (tripName ? '_' + tripName.replace(/[^a-zA-Z0-9]/g, '_') : '') + '.pdf';
  try {
    pdfMake.createPdf(docDef).download(filename);
    if (typeof toast === 'function') toast('Descargando lista…');
  } catch(e) {
    console.error('pdfmake error:', e);
    if (typeof toast === 'function') toast('Error al generar PDF');
  }
};

})();
